                    b.Property<int>("IdAccountingEntry")
                        .HasColumnType("int")
                        .HasColumnName("idAccountingEntry")
                        .HasComment("FK al asiento contable al que pertenece la línea.");

                    b.Property<int?>("IdCostCenter")
                        .HasColumnType("int")
                        .HasColumnName("idCostCenter")
